@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Dispatcher")]
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Shipment Dashboard</h2>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="ShowCreateForm">
        @(showCreate ? "Cancel" : "➕ New Shipment")
    </button>
</div>

@if (showCreate)
{
    <div class="card mb-4 p-3">
        <h5>Create Shipment</h5>
        <div class="row g-2">
            <div class="col-md-3">
                <input class="form-control" placeholder="Tracking #" @bind="newShipment.TrackingNumber" />
            </div>
            <div class="col-md-3">
                <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
            </div>
            <div class="col-md-3">
                <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
            </div>
            <div class="col-md-3">
                <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
            </div>
            <div class="col-md-4">
                <input class="form-control" placeholder="Description" @bind="newShipment.Description" />
            </div>
            <div class="col-md-3">
                <label class="form-label small">Shipped</label>
                <input type="date" class="form-control" @bind="newShipment.ShippedDate" />
            </div>
            <div class="col-md-3">
                <label class="form-label small">Est. Delivery</label>
                <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
            </div>
            <div class="col-md-2 d-flex align-items-end">
                <button class="btn btn-success" @onclick="CreateShipment">Create</button>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Length == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input class="form-control" placeholder="Filter by destination or tracking #..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td><strong>@s.TrackingNumber</strong></td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                    </td>
                    <td>@s.ShippedDate.ToString("yyyy-MM-dd")</td>
                    <td>@s.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                    <td>@s.CustomerEmail</td>
                    <td>
                        <select class="form-select form-select-sm" value="@s.Status"
                                @onchange="e => UpdateStatus(s, e.Value?.ToString())">
                            <option value="Pending">Pending</option>
                            <option value="In Transit">In Transit</option>
                            <option value="Customs Hold">Customs Hold</option>
                            <option value="Out for Delivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@if (!string.IsNullOrEmpty(message))
{
    <div class="alert alert-info mt-2">@message</div>
}

@code {
    private ShipmentDto[]? shipments;
    private string filterText = "";
    private bool showCreate;
    private ShipmentDto newShipment = new() { Status = "Pending", ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(7) };
    private string? message;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await Http.GetFromJsonAsync<ShipmentDto[]>("/api/shipments");
    }

    private void ShowCreateForm() => showCreate = !showCreate;

    private async Task CreateShipment()
    {
        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            message = $"Shipment {newShipment.TrackingNumber} created.";
            newShipment = new() { Status = "Pending", ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(7) };
            showCreate = false;
            await LoadShipments();
        }
        else
        {
            message = "Failed to create shipment.";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, string? newStatus)
    {
        if (string.IsNullOrEmpty(newStatus) || newStatus == shipment.Status) return;

        var response = await Http.PutAsJsonAsync($"/api/shipments/{shipment.Id}/status",
            new UpdateStatusRequest { Status = newStatus });

        if (response.IsSuccessStatusCode)
        {
            shipment.Status = newStatus;
            message = $"{shipment.TrackingNumber} updated to '{newStatus}'.";
        }
    }

    private static string GetStatusBadge(string status) => status switch
    {
        "Delivered" => "bg-success",
        "In Transit" => "bg-primary",
        "Pending" => "bg-warning text-dark",
        "Customs Hold" => "bg-danger",
        "Out for Delivery" => "bg-info text-dark",
        _ => "bg-secondary"
    };
}

@page "/my-shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>My Shipments</PageTitle>

<h2>My Shipments</h2>

@if (shipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (shipments.Length == 0)
{
    <p>You have no shipments. Use the tracking form below to look up a shipment.</p>
}
else
{
    <div class="row">
        @foreach (var s in shipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@s.TrackingNumber</strong>
                        <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                    </div>
                    <div class="card-body">
                        <p class="mb-1"><strong>From:</strong> @s.Origin</p>
                        <p class="mb-1"><strong>To:</strong> @s.Destination</p>
                        <p class="mb-1"><strong>Description:</strong> @s.Description</p>
                        <p class="mb-1"><strong>Shipped:</strong> @s.ShippedDate.ToString("MMM dd, yyyy")</p>
                        <p class="mb-0"><strong>Est. Delivery:</strong>
                            <span class="@(s.EstimatedDelivery < DateTime.Today && s.Status != "Delivered" ? "text-danger fw-bold" : "")">
                                @s.EstimatedDelivery.ToString("MMM dd, yyyy")
                            </span>
                        </p>
                    </div>
                </div>
            </div>
        }
    </div>
}

<hr />

<h4>Track a Shipment</h4>
<div class="input-group mb-3" style="max-width: 500px;">
    <input class="form-control" placeholder="Enter tracking number (e.g. TRK-20260001)"
           @bind="trackingNumber" @onkeydown="HandleKeyDown" />
    <button class="btn btn-outline-primary" @onclick="TrackShipment">Track</button>
</div>

@if (trackedShipment is not null)
{
    <div class="card border-primary" style="max-width: 500px;">
        <div class="card-header bg-primary text-white">
            @trackedShipment.TrackingNumber
        </div>
        <div class="card-body">
            <p><strong>Status:</strong> <span class="badge @GetStatusBadge(trackedShipment.Status)">@trackedShipment.Status</span></p>
            <p><strong>From:</strong> @trackedShipment.Origin</p>
            <p><strong>To:</strong> @trackedShipment.Destination</p>
            <p><strong>Description:</strong> @trackedShipment.Description</p>
            <p><strong>Shipped:</strong> @trackedShipment.ShippedDate.ToString("MMM dd, yyyy")</p>
            <p><strong>Estimated Delivery:</strong> @trackedShipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
        </div>
    </div>
}
else if (trackError is not null)
{
    <div class="alert alert-warning" style="max-width: 500px;">@trackError</div>
}

@code {
    private ShipmentDto[]? shipments;
    private string trackingNumber = "";
    private ShipmentDto? trackedShipment;
    private string? trackError;

    protected override async Task OnInitializedAsync()
    {
        shipments = await Http.GetFromJsonAsync<ShipmentDto[]>("/api/shipments/my");
    }

    private async Task TrackShipment()
    {
        trackedShipment = null;
        trackError = null;

        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        var response = await Http.GetAsync($"/api/shipments/track/{trackingNumber.Trim()}");
        if (response.IsSuccessStatusCode)
        {
            trackedShipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
        }
        else
        {
            trackError = $"No shipment found with tracking number '{trackingNumber}'.";
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static string GetStatusBadge(string status) => status switch
    {
        "Delivered" => "bg-success",
        "In Transit" => "bg-primary",
        "Pending" => "bg-warning text-dark",
        "Customs Hold" => "bg-danger",
        "Out for Delivery" => "bg-info text-dark",
        _ => "bg-secondary"
    };
}

